      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  if (f._convection) f._convection = null;
  else {
    changeLookupReadonly(f, 'ma_dvcs');
    var a = ['tk'];
    if (!f._extensions) f.request('GetDefaultValue', 'SetDefaultValue', a);
      else setReferenceValue(f, a);
  }
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, d1 = f.getItem('date_from').value, d2 = f.getItem('date_to').value, a = f.getItem('tk').value, q = f.getItemValue('chon_tt');
      g._hiddenFields = [{Fields: 'ps_no_nt, ps_co_nt, du_no_nt, du_co_nt, ma_nt, ty_gia', Value: (f.getItem('mau_bc').value == '10')}];
      g._alterTitle = [null, [['%s1', a, true], ['%d1', d1, true], ['%d2', d2, true]]];
      g._hiddenForms = [{Form: [0, 1, 2, 3, 4, 5, 6, 7, 8], Value: (q != '1')}, {Form: [9, 10, 11, 12, 13], Value: (q == '1')}];
      remove$GridReport$Filter(g);
      break;
    case 'SetDefaultValue':
      if (result[0].Value == '') f.setItemValue('tk', '');
        else f.setItemControlBehavior('ten_tk%l', result[0].Value, null, true);
      break;
    default:
       break;
  }
}
function setReferenceValue(f, a) {
  for (var i = 0; i < a.length; i++) {
    var r = $func.findField(a[i], f._fields).ItemReference;
    f.setItemValue(r, $func.findMemvar(r, f._extensions).NewValue);
  }
}
